class Solution {
    public int numSub(String s) {
        int res = 0, n = s.length(), mod = (int)1e9 + 7;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '1') {
                res = (res + (n - i)) % mod;
            }
        }
        return res;
    }
}
